static unsigned int TINY_SCANNER_DATA_LEN = 4373;

int TinyScanner::STATE_NUM;

int TinyScanner::INPUT_NUM;

int TinyScanner::DEAD_STATE;

bool* TinyScanner::ACCEPTS = nullptr;

int* TinyScanner::FA_TABLE = nullptr;

int* TinyScanner::BASES;

int TinyScanner::CAPACITY;

int* TinyScanner::CHECK;

int* TinyScanner::NEXTS;

int TinyScanner::OPT_TOP = 0;

int* TinyScanner::OPT_CMAP = nullptr;

int* TinyScanner::LEX_STATES = nullptr;

